(()=>{if(window.siteP2P)return;const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));let client=null;let viewerTorrent=null;let viewerStatusTimer=null;let activeStatusEl=null;let wtPromise=null;let swPromise=null;let serverStarted=false;const transfers=new Map();let xferSeq=0;let xferTimer=null;function vendorUrl(){const s=document.querySelector('script[data-vendor]');if(s&&s.dataset.vendor)return s.dataset.vendor;return'/assets/js/vendor/webtorrent.min.js';}
function swUrl(){const s=document.querySelector('script[data-sw]');if(s&&s.dataset.sw)return s.dataset.sw;return'/sw.min.js';}
function loadWebTorrent(){if(window.WebTorrent)return Promise.resolve(window.WebTorrent);if(wtPromise)return wtPromise;wtPromise=import(vendorUrl()).then(mod=>{window.WebTorrent=mod.default||mod.WebTorrent;return window.WebTorrent;}).catch(err=>{wtPromise=null;throw err;});return wtPromise;}
function registerSW(){if(swPromise)return swPromise;if(!('serviceWorker'in navigator)){swPromise=Promise.resolve(null);return swPromise;}
swPromise=navigator.serviceWorker.register(swUrl()).then(reg=>{const worker=reg.active||reg.waiting||reg.installing;if(!worker)return reg;if(worker.state==='activated')return reg;return new Promise((resolve)=>{worker.addEventListener('statechange',()=>{if(worker.state==='activated')resolve(reg);});});}).catch(err=>{console.warn('p2p: sw register failed, falling back to blob mode',err);return null;});return swPromise;}
function defaultStatus(){return document.querySelector('#panel [data-p2p-status]')||document.querySelector('[data-p2p-status]');}
function defaultStage(){return document.querySelector('#panel [data-p2p-stage]')||document.querySelector('[data-p2p-stage]');}
function setStatus(t){const el=activeStatusEl||defaultStatus();if(el)el.textContent=t;}
function fmtBytes(n){if(!n||n<0)return'0 B';const u=['B','KB','MB','GB','TB'];let i=0;while(n>=1024&&i<u.length-1){n /=1024;i++;}
return n.toFixed(n<10?1:0)+' '+u[i];}
function watchViewer(t){if(viewerStatusTimer)clearInterval(viewerStatusTimer);viewerStatusTimer=setInterval(()=>{if(t.done){setStatus('peers '+t.numPeers+' · ↑ '+fmtBytes(t.uploadSpeed)+'/s');}else{const pct=(t.progress*100).toFixed(0);setStatus('peers '+t.numPeers+' · '+pct+'% · ↓ '+fmtBytes(t.downloadSpeed)+'/s');}},800);t.on('error',(err)=>setStatus('error: '+(err&&err.message?err.message:err)));t.on('warning',()=>{});}
async function ensureClient(){await loadWebTorrent();if(!client)client=new window.WebTorrent();if(!serverStarted){const reg=await registerSW();if(reg&&typeof client.createServer==='function'){try{client.createServer({controller:reg});serverStarted=true;}catch(e){console.warn('p2p: createServer failed, falling back to blob mode',e);}}}
return client;}
function clearEl(el){if(!el)return;while(el.firstChild)el.removeChild(el.firstChild);el.classList.remove('vid-frame-empty');}
function pickFile(t){if(!t.files||!t.files.length)return null;return t.files.slice().sort((a,b)=>b.length-a.length)[0];}
function buildRenderEl(kind,src,fileName){let el;if(kind==='video'){el=document.createElement('video');el.controls=true;el.autoplay=true;el.className='vid-frame';el.style.objectFit='contain';el.style.background='#000';}else if(kind==='audio'){el=document.createElement('audio');el.controls=true;el.autoplay=true;el.style.width='100%';}else if(kind==='image'){el=document.createElement('img');el.alt=fileName;el.style.maxWidth='100%';el.style.height='auto';}else if(kind==='pdf'){el=document.createElement('iframe');el.style.width='100%';el.style.minHeight='70vh';el.style.border='0';}else{el=document.createElement('a');el.download=fileName;el.textContent='⤓ '+fileName;el.className='ui-badge';}
el.src=src;return el;}
async function fileBlobURL(file){if(typeof file.blob==='function'){const b=await file.blob();return URL.createObjectURL(b);}
if(typeof file.getBlobURL==='function'){return new Promise((resolve,reject)=>{file.getBlobURL((err,url)=>err?reject(err):resolve(url));});}
throw new Error('no blob API on file');}
function infoHashOf(magnet){const m=/xt=urn:btih:([a-z0-9]+)/i.exec(magnet||'');return m?m[1].toLowerCase():'';}
function sameMagnet(t,magnet){try{return!!(t&&t.infoHash&&t.infoHash.toLowerCase()===infoHashOf(magnet));}
catch(_){return false;}}
function managerOwns(t){if(!t)return false;for(const e of transfers.values())if(e.torrent===t)return true;return false;}
async function open(magnet,kind,stage,statusEl){activeStatusEl=statusEl||null;setStatus('connecting…');const target=stage||defaultStage();try{const c=await ensureClient();if(viewerTorrent&&!managerOwns(viewerTorrent)){try{viewerTorrent.destroy();}catch(_){}}
viewerTorrent=null;clearEl(target);const onReady=(t)=>{viewerTorrent=t;watchViewer(t);const file=pickFile(t);if(!file){setStatus('no files in torrent');return;}
if(serverStarted&&typeof file.streamURL==='string'){if(target)target.appendChild(buildRenderEl(kind,file.streamURL,file.name));return;}
fileBlobURL(file).then(url=>{if(target)target.appendChild(buildRenderEl(kind,url,file.name));}).catch(e=>setStatus('render: '+(e.message||e)));};let existing=null;try{const g=c.get(magnet);existing=(g&&g.then)?await g:g;}catch(_){}
if(existing)onReady(existing);else c.add(magnet,onReady);}catch(e){setStatus('error: '+(e.message||e));}}
function copy(magnet,statusEl){activeStatusEl=statusEl||null;if(!navigator.clipboard){setStatus('clipboard unavailable');return;}
navigator.clipboard.writeText(magnet).then(()=>setStatus('copied'),()=>setStatus('copy failed'));}
function xt(key,fallback){const el=document.querySelector('[data-xfer-list]');return(el&&el.dataset[key])||fallback;}
const KIND={pdf:'PDF',epub:'EPB',audio:'AUD',video:'VID',image:'IMG',archive:'ZIP',other:'OTH'};function kindTag(k){return'['+(KIND[k]||'OTH')+']';}
function kindFromName(name){const ext=(String(name).split('.').pop()||'').toLowerCase();if(ext==='pdf')return'pdf';if(ext==='epub')return'epub';if(['mp4','mkv','webm','mov','avi','m4v'].includes(ext))return'video';if(['mp3','wav','flac','ogg','m4a','aac'].includes(ext))return'audio';if(['jpg','jpeg','png','gif','webp','svg','avif'].includes(ext))return'image';if(['zip','tar','gz','7z','rar','xz'].includes(ext))return'archive';return'other';}
const CREATE_TRACKERS=['udp://tracker.opentrackr.org:1337/announce','udp://open.tracker.cl:1337/announce','udp://tracker.openbittorrent.com:6969/announce','udp://exodus.desync.com:6969/announce','udp://tracker.torrent.eu.org:451/announce','wss://tracker.openwebtorrent.com','wss://tracker.webtorrent.dev','wss://tracker.btorrent.xyz',];const BAR_W=16;function bar(p){const f=Math.max(0,Math.min(BAR_W,Math.round((p||0)*BAR_W)));return'['+'█'.repeat(f)+'░'.repeat(BAR_W-f)+']';}
function swarm(t){if(!t)return{s:'—',p:0,l:0};const p=t.numPeers||0;let s=0;try{const n=t.pieces?t.pieces.length:0;if(n&&n<=6000&&t.wires){t.wires.forEach(w=>{const pp=w&&w.peerPieces;if(!pp)return;let all=true;for(let i=0;i<n;i++){if(!pp.get(i)){all=false;break;}}
if(all)s++;});}else{return{s:'—',p:p,l:'—'};}}catch(_){return{s:'—',p:p,l:'—'};}
return{s:s,p:p,l:Math.max(0,p-s)};}
function announceOpen(){document.dispatchEvent(new CustomEvent('ui:open-drawer',{detail:{name:'xfer'}}));}
function ensureXferTimer(){if(!xferTimer)xferTimer=setInterval(paintAll,800);}
function setEmpty(){const empty=document.querySelector('[data-xfer-empty]');if(empty)empty.hidden=transfers.size>0;}
function renderRow(entry){const list=document.querySelector('[data-xfer-list]');if(!list)return;const li=document.createElement('li');li.className='xfer-row';li.dataset.xferId=entry.id;li.innerHTML='<div class="xfer-l1">'
+'<span class="xfer-kind ui-sku"></span>'
+'<span class="xfer-name"></span>'
+'<span class="xfer-act">'
+'<button type="button" class="xfer-btn" data-xfer-pause></button>'
+'<button type="button" class="xfer-btn" data-xfer-copy>↗</button>'
+'<button type="button" class="xfer-btn" data-xfer-remove>✕</button>'
+'</span>'
+'</div>'
+'<div class="xfer-l2 ui-sku">'
+'<span class="xfer-bar" aria-hidden="true"></span> '
+'<span class="xfer-pct"></span> · '
+'<span class="xfer-state"></span>'
+'<span class="xfer-net"></span>'
+'<span class="xfer-swarm"></span>'
+'</div>';entry.dom=li;entry.els={kind:li.querySelector('.xfer-kind'),name:li.querySelector('.xfer-name'),bar:li.querySelector('.xfer-bar'),pct:li.querySelector('.xfer-pct'),state:li.querySelector('.xfer-state'),net:li.querySelector('.xfer-net'),swarm:li.querySelector('.xfer-swarm'),pause:li.querySelector('[data-xfer-pause]'),copy:li.querySelector('[data-xfer-copy]'),remove:li.querySelector('[data-xfer-remove]'),};entry.els.remove.setAttribute('aria-label',xt('lblRemove','Remove'));entry.els.copy.setAttribute('aria-label',xt('lblCopy','Copy magnet'));list.appendChild(li);setEmpty();paintRow(entry);}
function paintRow(entry){if(!entry.els)return;const t=entry.torrent;const done=!!(entry.done||(t&&t.done));const prog=done?1:(t?t.progress:0);let state;if(entry.error)state='error';else if(entry.paused)state=xt('stPaused','paused');else if(!t)state=xt('stConnecting','connecting…');else if(done)state=(entry.mode==='download'&&entry.saved&&!entry.savedAck)?xt('stSaved','saved'):xt('stSeeding','seeding');else state=xt('stDownloading','downloading');entry.els.kind.textContent=kindTag(entry.kind);entry.els.name.textContent=entry.name||'…';entry.els.name.title=entry.name||'';entry.els.bar.textContent=bar(prog);entry.els.pct.textContent=Math.round(prog*100)+'%';entry.els.state.textContent=state;entry.els.net.textContent=' ↓'+fmtBytes(t?t.downloadSpeed:0)+'/s ↑'+fmtBytes(t?t.uploadSpeed:0)+'/s';const sw=swarm(t);entry.els.swarm.textContent=' S'+sw.s+' P'+sw.p+' L'+sw.l;entry.els.pause.textContent=entry.paused?'▶':'▮▮';entry.els.pause.setAttribute('aria-label',entry.paused?xt('lblResume','Resume'):xt('lblPause','Pause'));entry.els.pause.disabled=!t;entry.els.copy.disabled=!entry.magnet;entry.dom.dataset.state=entry.error?'error':entry.paused?'paused':done?'seeding':t?'downloading':'connecting';}
function paintAll(){transfers.forEach(paintRow);paintSummary();}
function paintSummary(){let dn=0,up=0;transfers.forEach(e=>{const t=e.torrent;if(t){dn+=t.downloadSpeed||0;up+=t.uploadSpeed||0;}});const n=transfers.size;$$('[data-xfer-summary]').forEach(el=>{el.textContent=n?('↓'+fmtBytes(dn)+'/s ↑'+fmtBytes(up)+'/s'):'';});$$('[data-drawer-toggle="xfer"]').forEach(b=>{b.classList.toggle('xfer-live',n>0);const c=b.querySelector('[data-xfer-count]');if(c)c.textContent=n?String(n):'';});setEmpty();}
function onDone(entry){if(entry.done)return;entry.done=true;if(entry.mode==='download'&&!entry.saved){saveEntry(entry);return;}
paintRow(entry);}
function saveEntry(entry){const t=entry.torrent;const file=t&&pickFile(t);if(!file)return;fileBlobURL(file).then(url=>{const a=document.createElement('a');a.href=url;a.download=file.name;document.body.appendChild(a);a.click();a.remove();entry.saved=true;paintRow(entry);setTimeout(()=>{entry.savedAck=true;paintRow(entry);},2500);}).catch(()=>{});}
function bindTorrent(entry,t){entry.torrent=t;if(!entry.name)entry.name=(pickFile(t)&&pickFile(t).name)||t.name||'';t.on('error',()=>{entry.error='error';paintRow(entry);});t.on('warning',()=>{});t.on('done',()=>onDone(entry));if(t.done)onDone(entry);ensureXferTimer();paintRow(entry);}
async function attachTorrent(entry){let c;try{c=await ensureClient();}
catch(e){entry.error=String(e.message||e);paintRow(entry);return;}
if(viewerTorrent&&sameMagnet(viewerTorrent,entry.magnet)){bindTorrent(entry,viewerTorrent);return;}
let existing=null;try{const g=c.get(entry.magnet);existing=(g&&g.then)?await g:g;}catch(_){}
if(existing){bindTorrent(entry,existing);return;}
try{c.add(entry.magnet,t=>bindTorrent(entry,t));}
catch(e){try{const g=c.get(entry.magnet);const t=(g&&g.then)?await g:g;if(t){bindTorrent(entry,t);return;}}catch(_){}
entry.error=String(e.message||e);paintRow(entry);}}
function addTransfer(magnet,opts){if(!magnet)return null;opts=opts||{};for(const e of transfers.values()){if(e.magnet===magnet){announceOpen();return e.id;}}
const id='x'+(xferSeq++);const entry={id,magnet,name:opts.name||'',kind:opts.kind||'other',mode:opts.mode==='seed'?'seed':'download',torrent:null,paused:false,done:false,saved:false,error:'',};transfers.set(id,entry);renderRow(entry);announceOpen();paintSummary();attachTorrent(entry);return id;}
function download(magnet,opts){return addTransfer(magnet,Object.assign({mode:'download'},opts||{}));}
function seedAll(magnets,names,kinds){if(!magnets||!magnets.length)return;magnets.forEach((m,i)=>addTransfer(m,{mode:'seed',name:names&&names[i],kind:kinds&&kinds[i]}));}
async function seedFiles(fileList){const files=Array.from(fileList||[]);if(!files.length)return;let c;try{c=await ensureClient();}
catch(_){return;}
files.forEach(file=>{const id='x'+(xferSeq++);const entry={id,magnet:'',name:file.name,kind:kindFromName(file.name),mode:'seed',torrent:null,paused:false,done:false,saved:false,error:'',};transfers.set(id,entry);renderRow(entry);announceOpen();paintSummary();try{c.seed(file,{announce:CREATE_TRACKERS},(torrent)=>{entry.torrent=torrent;entry.magnet=torrent.magnetURI;entry.done=true;torrent.on('error',()=>{entry.error='error';paintRow(entry);});torrent.on('warning',()=>{});ensureXferTimer();paintRow(entry);});}catch(e){entry.error=String(e.message||e);paintRow(entry);}});}
function addMagnetFromInput(){const inp=document.querySelector('[data-xfer-magnet-input]');if(!inp)return;const v=(inp.value||'').trim();let magnet='';if(/^magnet:\?/i.test(v))magnet=v;else{const m=v.match(/\b([a-f0-9]{40})\b/i);if(m)magnet='magnet:?xt=urn:btih:'+m[1];}
if(!magnet){inp.focus();return;}
const dn=(magnet.match(/[?&]dn=([^&]+)/i)||[])[1];download(magnet,{name:dn?decodeURIComponent(dn.replace(/\+/g,' ')):''});inp.value='';const row=document.querySelector('[data-xfer-magnet-row]');if(row)row.hidden=true;}
function pause(id){const e=transfers.get(id);if(!e||!e.torrent)return;try{e.torrent.pause();}catch(_){}e.paused=true;paintRow(e);}
function resume(id){const e=transfers.get(id);if(!e||!e.torrent)return;try{e.torrent.resume();}catch(_){}e.paused=false;paintRow(e);}
function remove(id){const e=transfers.get(id);if(!e)return;transfers.delete(id);if(e.dom)e.dom.remove();if(e.torrent){if(viewerTorrent===e.torrent)viewerTorrent=null;try{e.torrent.destroy();}catch(_){}}
if(!transfers.size&&xferTimer){clearInterval(xferTimer);xferTimer=null;}
paintSummary();}
function teardown(){if(viewerStatusTimer){clearInterval(viewerStatusTimer);viewerStatusTimer=null;}
if(viewerTorrent&&!managerOwns(viewerTorrent)){try{viewerTorrent.destroy();}catch(_){}}
viewerTorrent=null;activeStatusEl=null;}
function init(){document.addEventListener('click',(e)=>{const pz=e.target.closest('[data-xfer-pause]');if(pz){const row=pz.closest('[data-xfer-id]');const en=row&&transfers.get(row.dataset.xferId);if(en)(en.paused?resume:pause)(en.id);return;}
const cp=e.target.closest('[data-xfer-copy]');if(cp){const row=cp.closest('[data-xfer-id]');const en=row&&transfers.get(row.dataset.xferId);if(en&&en.magnet&&navigator.clipboard){navigator.clipboard.writeText(en.magnet).then(()=>{const o=cp.textContent;cp.textContent='✓';setTimeout(()=>{cp.textContent=o;},900);},()=>{});}
return;}
const rm=e.target.closest('[data-xfer-remove]');if(rm){const row=rm.closest('[data-xfer-id]');if(row)remove(row.dataset.xferId);return;}
const addBtn=e.target.closest('[data-xfer-add]');if(addBtn){const inp=document.querySelector('[data-xfer-file]');if(inp)inp.click();return;}
const mg=e.target.closest('[data-xfer-magnet]');if(mg){const row=document.querySelector('[data-xfer-magnet-row]');if(row){row.hidden=!row.hidden;if(!row.hidden){const i=row.querySelector('[data-xfer-magnet-input]');if(i)i.focus();}}
return;}
const mgo=e.target.closest('[data-xfer-magnet-go]');if(mgo){e.preventDefault();addMagnetFromInput();return;}
const btn=e.target.closest('[data-p2p-action]');if(!btn)return;e.preventDefault();const a=btn.dataset.p2pAction;const m=btn.dataset.magnet;const k=btn.dataset.kind||'other';if(!m)return;if(a==='copy')copy(m);else if(a==='download')download(m,{name:btn.dataset.title,kind:k});else if(a==='open')open(m,k);});document.addEventListener('change',(e)=>{const inp=e.target.closest('[data-xfer-file]');if(!inp)return;seedFiles(inp.files);inp.value='';});document.addEventListener('submit',(e)=>{if(e.target.closest('[data-xfer-magnet-row]')){e.preventDefault();addMagnetFromInput();}});addEventListener('beforeunload',()=>{try{teardown();}catch(_){}
if(client){try{client.destroy();}catch(_){}client=null;}});}
window.siteP2P={teardown,init,open,copy,download,seedAll,seedFiles,pause,resume,remove};init();})();
